CREATE OR REPLACE FUNCTION public.update_sale_probe(_sale_id uuid, _items jsonb) RETURNS uuid LANGUAGE plpgsql SECURITY DEFINER SET search_path = public AS $$ DECLARE _item JSONB; _qty NUMERIC; _price NUMERIC; _subtotal NUMERIC := 0; _idisc NUMERIC; _trate NUMERIC; _tax NUMERIC; _line NUMERIC; _tax_total NUMERIC := 0; _item_disc_total NUMERIC := 0; BEGIN FOR _item IN SELECT * FROM jsonb_array_elements(_items) LOOP _qty := (_item->>'quantity')::NUMERIC; _price := (_item->>'unit_price')::NUMERIC; _idisc := COALESCE(NULLIF(_item->>'discount_amount','')::NUMERIC, 0); _trate := COALESCE(NULLIF(_item->>'tax_rate','')::NUMERIC, 0); _line := (_qty * _price) - _idisc; _tax := ROUND(_line * _trate / 100.0, 2); _subtotal := _subtotal + (_qty * _price); _item_disc_total := _item_disc_total + _idisc; _tax_total := _tax_total + _tax; END LOOP; RETURN _sale_id; END; $$;